import React, { useState, useEffect } from 'react';

function App() {
  const [books, setBooks] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('http://localhost:5000/api/products')
      .then(res => {
        if (!res.ok) {
          throw new Error('Server returned status: ' + res.status);
        }
        return res.json();
      })
      .then(data => setBooks(data))
      .catch(err => {
        console.error(err);
        setError('Failed to load books: ' + err.message);
      });
  }, []);

  return (
    <div style={{ padding: '40px', fontFamily: 'Arial, sans-serif', backgroundColor: '#f4f7f6', minHeight: '100vh' }}>
      <h1 style={{ textAlign: 'center', color: '#333', marginBottom: '40px', fontWeight: 'bold' }}>Bookstore Platform</h1>
      
      {error && (
        <div style={{ color: 'red', textAlign: 'center', marginBottom: '20px', fontWeight: 'bold' }}>
          {error}
        </div>
      )}
      
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(3, 1fr)', 
        gap: '30px', 
        maxWidth: '1000px', 
        margin: '0 auto' 
      }}>
        {books.map(book => (
          <div key={book.id} style={{ 
            backgroundColor: '#fff', 
            padding: '20px', 
            borderRadius: '12px', 
            boxShadow: '0 4px 12px rgba(0,0,0,0.08)', 
            display: 'flex', 
            flexDirection: 'column', 
            alignItems: 'center',
            textAlign: 'center'
          }}>
            <img 
              src="https://images.unsplash.com/photo-1543002588-bfa74002ed7e?w=500&auto=format&fit=crop&q=60" 
              alt="Book Cover" 
              style={{ width: '140px', height: '200px', objectFit: 'cover', borderRadius: '6px', marginBottom: '15px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}
            />
            <h3 style={{ margin: '10px 0 5px 0', color: '#2c3e50', fontSize: '18px', height: '44px', overflow: 'hidden' }}>{book.title}</h3>
            <p style={{ margin: '5px 0', color: '#7f8c8d', fontSize: '14px' }}><strong>Author:</strong> {book.author}</p>
            <p style={{ margin: '5px 0', color: '#bdc3c7', fontSize: '12px', backgroundColor: '#session', padding: '3px 8px', borderRadius: '12px', display: 'inline-block' }}>{book.category}</p>
            <p style={{ margin: '15px 0', fontWeight: 'bold', color: '#27ae60', fontSize: '20px' }}>${book.price}</p>
            <button style={{ 
              backgroundColor: '#007bff', 
              color: '#fff', 
              border: 'none', 
              padding: '10px 20px', 
              borderRadius: '6px', 
              cursor: 'pointer', 
              fontWeight: 'bold',
              width: '100%',
              marginTop: 'auto'
            }}>Buy Now</button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
